import{_ as t,o as l,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"مرجع Scalerها (Scaler Reference)","description":"","frontmatter":{},"headers":[],"relativePath":"fa/scalers/reference.md","filePath":"fa/scalers/reference.md"}'),d={name:"fa/scalers/reference.md"};function o(n,e,i,s,c,g){return l(),a("div",null,[...e[0]||(e[0]=[r('<div dir="rtl"><h1 id="مرجع-scalerها-scaler-reference" tabindex="-1"><i class="ph ph-sliders"></i> مرجع Scalerها (Scaler Reference) <a class="header-anchor" href="#مرجع-scalerها-scaler-reference" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-sliders&quot;&gt;&lt;/i&gt; مرجع Scalerها (Scaler Reference)&quot;">​</a></h1><p>ابزار Web Adaptive Performance شامل مجموعه‌ای از Scalerهای تخصصی (ماژول‌های بهینه‌سازی) است. Indexer به‌طور خودکار انتخاب می‌کند که کدام Scaler را بر اساس تأثیر بصری (<code>Visual Impact</code>) و نوع گلوگاه فعلی (<code>Target</code>: پردازنده یا کارت گرافیک) اعمال کند.</p><h2 id="ماتریس-سازگاری" tabindex="-1">ماتریس سازگاری <a class="header-anchor" href="#ماتریس-سازگاری" aria-label="Permalink to &quot;ماتریس سازگاری&quot;">​</a></h2><p>در زیر ماتریس سازگاری و شرحی از تمام ماژول‌های موجود آورده شده است.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Scaler</th><th style="text-align:left;">Pipeline</th><th style="text-align:left;">Target</th><th style="text-align:left;">توضیحات</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Resolution</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">وضوح رندرینگ (Rendering Resolution) را کاهش می‌دهد و بار روی Fillrate کارت گرافیک را به‌شدت کم می‌کند. <em>جزئیات را در ادامه ببینید.</em></td></tr><tr><td style="text-align:left;"><strong>Shadows Quality</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">سایه‌ها را به‌صورت مرحله‌ای غیرفعال می‌کند.<br>در <strong>URP</strong>، ابتدا سایه‌های نرم (Soft Shadows)، سپس سایه نورهای اضافی، و در نهایت سایه اصلی را غیرفعال می‌کند.<br>در <strong>BiRP</strong>، سایه‌ها را قبل از غیرفعال کردن کامل، به حالت <code>Hard Only</code> تغییر می‌دهد.</td></tr><tr><td style="text-align:left;"><strong>Shadow Cascades</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU/GPU</td><td style="text-align:left;">تعداد Cascades سایه‌ها را کاهش می‌دهد. Draw Callهای پردازنده و بار کارت گرافیک را کاهش می‌دهد.</td></tr><tr><td style="text-align:left;"><strong>Shadow Distance</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">فاصله رسم (Draw Distance) سایه‌ها را کوتاه می‌کند.</td></tr><tr><td style="text-align:left;"><strong>Shadow Resolution</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">وضوح نقشه‌های سایه (Shadow Maps) را کاهش می‌دهد.</td></tr><tr><td style="text-align:left;"><strong>Anti Aliasing</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">کیفیت Anti-Aliasing (MSAA) را تا غیرفعال شدن کامل آن کاهش می‌دهد.</td></tr><tr><td style="text-align:left;"><strong>LOD Bias</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">موتور Unity را مجبور می‌کند تا در فواصل کوتاه‌تر به مدل‌های LOD با تعداد چندضلعی کمتر (Low-poly) سوییچ کند.</td></tr><tr><td style="text-align:left;"><strong>Camera Clip</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">پارامتر <code>Far Clip Plane</code> را در دوربین‌های هدف کاهش داده و اشیاء دور را از رندرینگ حذف می‌کند.</td></tr><tr><td style="text-align:left;"><strong>Layer Culling</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU</td><td style="text-align:left;">فاصله Culling (حذف اشیاء دور از دید) را برای لایه‌های خاصی از اشیاء به‌تناسب کاهش می‌دهد.</td></tr><tr><td style="text-align:left;"><strong>Physics Step</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU</td><td style="text-align:left;">فرکانس محاسبات فیزیک را کاهش می‌دهد. در هنگام بارهای سنگین فیزیکی در مرورگر، به حفظ عملکرد کمک می‌کند.</td></tr><tr><td style="text-align:left;"><strong>LUT</strong></td><td style="text-align:left;"><code>فقط URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">اندازه جداول LUT در Color Grading را به حداقل می‌رساند.</td></tr><tr><td style="text-align:left;"><strong>Mesh LOD Threshold</strong></td><td style="text-align:left;"><code>Unity 6+</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">پارامتر <code>meshLodThreshold</code> معرفی‌شده در Unity 6.2 را برای تغییرات تهاجمی‌تر LOD تغییر می‌دهد.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">احتیاط با Physics Step Scaler</p><p>اسکیلر فیزیک مستقیماً پارامتر <code>Time.fixedDeltaTime</code> را تغییر می‌دهد. اگر کنترلر کاراکتر (Character Controller) یا مکانیک‌های بازی شما به‌طور سخت‌گیرانه به فریم‌های فیزیک ثابت بدون درونیابی (Interpolation) متکی باشند، حرکت اشیاء ممکن است در سطوح کیفیت پایین‌تر دچار پرش (Stuttering) شود.</p></div><div class="tip custom-block"><p class="custom-block-title">تنظیم مجدد Scaler</p><p>اگر با پارامترهای Scaler آزمایش کرده‌اید (مثلاً <code>Min Bound</code> یا <code>Max Level</code> را تغییر داده‌اید) و می‌خواهید به مقادیر پیش‌فرض بازگردید، کافیست سوئیچ آن را در پنجره <em>Project Settings</em> خاموش و روشن کنید. افزونه به‌طور خودکار ماژول را با پیکربندی پایه از نو می‌سازد.</p></div><h2 id="بررسی-عمیق-resolution-scaler" tabindex="-1">بررسی عمیق: Resolution Scaler <a class="header-anchor" href="#بررسی-عمیق-resolution-scaler" aria-label="Permalink to &quot;بررسی عمیق: Resolution Scaler&quot;">​</a></h2><p>این قدرتمندترین ابزار افزونه است که بیشترین افزایش FPS را تضمین می‌کند. نحوه عملکرد آن بسته به پایپ‌لاین (Pipeline) فعال بسیار متفاوت است.</p><h3 id="در-حالت-urp-universal-render-pipeline" tabindex="-1">در حالت URP (Universal Render Pipeline) <a class="header-anchor" href="#در-حالت-urp-universal-render-pipeline" aria-label="Permalink to &quot;در حالت URP (Universal Render Pipeline)&quot;">​</a></h3><p>در URP، مقیاس‌بندی (Scaling) بدون نقص کار می‌کند. افزونه مستقیماً با ویژگی <code>renderScale</code> در <code>UniversalRenderPipelineAsset</code> تعامل می‌کند. رابط کاربری (UI) به‌طور خودکار واضح می‌ماند، زیرا URP می‌تواند Canvas را روی یک دنیای سه‌بعدی که مقیاس آن تغییر کرده است، رندر کند.</p><h3 id="در-حالت-birp-built-in-render-pipeline" tabindex="-1">در حالت BiRP (Built-in Render Pipeline) <a class="header-anchor" href="#در-حالت-birp-built-in-render-pipeline" aria-label="Permalink to &quot;در حالت BiRP (Built-in Render Pipeline)&quot;">​</a></h3><p>از نظر تاریخی، BiRP فاقد تنظیمات Render Scale داخلی است که بتواند در WebGL بدون خراب کردن رابط کاربری یا ایجاد خطا (مانند FBO Feedback Loop) کار کند. WebAP این مشکل را با ارائه دو استراتژی انحصاری حل می‌کند.</p><h4 id="حالت-۱-nativebrowserscaling-مقیاس‌بندی-بومی-مرورگر" tabindex="-1">حالت ۱: NativeBrowserScaling (مقیاس‌بندی بومی مرورگر) <a class="header-anchor" href="#حالت-۱-nativebrowserscaling-مقیاس‌بندی-بومی-مرورگر" aria-label="Permalink to &quot;حالت ۱: NativeBrowserScaling (مقیاس‌بندی بومی مرورگر)&quot;">​</a></h4><p>افزونه عنصر HTML <code>&lt;canvas&gt;</code> را مستقیماً از طریق فریب دادن حلقه بومی (Native Loop Spoofing) (با تزریق به پارامترهای <code>devicePixelRatio</code> مرورگر) مقیاس‌بندی می‌کند.</p><ul><li><strong>مزایا:</strong> حداکثر عملکرد، بدون هزینه پردازشی اضافی (Zero Overhead) روی کارت گرافیک.</li><li><strong>معایب:</strong> رابط کاربری بازی همراه با گرافیک سه‌بعدی تار می‌شود. این حالت فقط در نسخه کامپایل‌شده WebGL عمل می‌کند (تغییرات در داخل Unity Editor قابل مشاهده نیستند).</li></ul><h4 id="حالت-۲-rendertexturescaling" tabindex="-1">حالت ۲: RenderTextureScaling <a class="header-anchor" href="#حالت-۲-rendertexturescaling" aria-label="Permalink to &quot;حالت ۲: RenderTextureScaling&quot;">​</a></h4><p>افزونه خروجی دوربین‌های هدف را به یک بافت اشتراکی (Shared Texture) فشرده‌شده هدایت (Redirect) می‌کند و از یک دوربین ترکیبی پنهان (Compositor Camera) برای ارائه تصویر استفاده می‌کند.</p><ul><li><strong>مزایا:</strong> دنیای سه‌بعدی تغییر مقیاس می‌دهد، در حالی که رابط کاربری (متن، دکمه‌ها) کاملاً واضح می‌ماند.</li><li><strong>معایب:</strong> به دلیل عملیات Blit (کپی کردن بافت به صفحه نمایش) بار جزئی به کارت گرافیک اضافه می‌کند.</li></ul><div class="info custom-block"><p class="custom-block-title">اصلاح کلیک‌های ماوس (Raycasts)</p><p>هنگام استفاده از RenderTextureScaling، مختصات مجازی صفحه فشرده می‌شود. برای اطمینان از اینکه کلیک‌های ماوس روی اشیاء سه‌بعدی به‌درستی کار می‌کنند، افزونه به‌طور خودکار کامپوننت‌های استاندارد <code>PhysicsRaycaster</code> و <code>Physics2DRaycaster</code> در دوربین‌های هدف را با کامپوننت‌های سفارشی <code>WebScaledPhysicsRaycaster</code> جایگزین می‌کند. دقت Rayها در هر مقیاسی بی‌نقص باقی می‌ماند.</p></div><h2 id="چگونه-وضوح-ui-را-حفظ-کنیم؟-برای-birp-rendertexturescaling" tabindex="-1">چگونه وضوح UI را حفظ کنیم؟ (برای BiRP RenderTextureScaling) <a class="header-anchor" href="#چگونه-وضوح-ui-را-حفظ-کنیم؟-برای-birp-rendertexturescaling" aria-label="Permalink to &quot;چگونه وضوح UI را حفظ کنیم؟ (برای BiRP RenderTextureScaling)&quot;">​</a></h2><p>برای واضح نگه‌داشتن رابط کاربری در حین مقیاس‌بندی گرافیک سه‌بعدی در BiRP با RenderTextureScaling، باید Canvas خود را به‌درستی پیکربندی کنید. یکی از این دو گزینه را انتخاب کنید:</p><h3 id="گزینه-۱-screen-space-overlay-توصیه-شده" tabindex="-1">گزینه ۱: Screen Space - Overlay (توصیه شده) <a class="header-anchor" href="#گزینه-۱-screen-space-overlay-توصیه-شده" aria-label="Permalink to &quot;گزینه ۱: Screen Space - Overlay (توصیه شده)&quot;">​</a></h3><p>ساده‌ترین و مطمئن‌ترین روش. افزونه تمام کارها را به‌طور خودکار انجام می‌دهد.<br> ۱. <strong>Canvas</strong> خود را در Hierarchy صحنه انتخاب کنید.<br> ۲. در کامپوننت Canvas، ویژگی <strong>Render Mode</strong> را روی <code>Screen Space - Overlay</code> تنظیم کنید.<br><em>نتیجه:</em> Unity رابط کاربری را روی دنیای سه‌بعدیِ فشرده‌شده، با وضوح ۱۰۰٪ بومی رندر می‌کند.</p><h3 id="گزینه-۲-screen-space-camera-برای-لایه‌های-پیچیده" tabindex="-1">گزینه ۲: Screen Space - Camera (برای لایه‌های پیچیده) <a class="header-anchor" href="#گزینه-۲-screen-space-camera-برای-لایه‌های-پیچیده" aria-label="Permalink to &quot;گزینه ۲: Screen Space - Camera (برای لایه‌های پیچیده)&quot;">​</a></h3><p>اگر نیاز به ترکیب مدل‌های سه‌بعدی، ذرات (Particles) و رابط کاربری دارید از این روش استفاده کنید. باید رندرینگ را به دو دوربین جداگانه تفکیک کنید.<br> ۱. <strong>دوربین اصلی (سه‌بعدی):</strong> مطمئن شوید که تگ (Tag) آن در آرایه <code>Target Tags</code> تنظیمات Scaler مشخص شده باشد. در فیلد <code>Culling Mask</code>، تیک لایه <strong>UI</strong> را بردارید. ویژگی <code>Depth</code> را روی <code>0</code> تنظیم کنید.<br> ۲. <strong>دوربین رابط کاربری (جدید):</strong> یک دوربین جدید برای رندر کردن رابط کاربری ایجاد کنید. تگ آن را به تنظیمات Scaler <strong>اضافه نکنید</strong>.<br> * ویژگی <code>Clear Flags</code> را روی <code>Depth Only</code> تنظیم کنید (تا دوربین پس‌زمینه سه‌بعدی را پاک نکند).<br> * ویژگی <code>Culling Mask</code> را فقط به لایه <strong>UI</strong> اختصاص دهید.<br> * ویژگی <code>Depth</code> را روی <code>1</code> (بیشتر از دوربین اصلی) تنظیم کنید.<br> ۳. <strong>تنظیمات Canvas:</strong> ویژگی <strong>Render Mode</strong> را روی <code>Screen Space - Camera</code> تنظیم کنید و دوربین رابط کاربری جدید خود را به فیلد <code>Render Camera</code> بکشید.</p></div>',1)])])}const f=t(d,[["render",o]]);export{h as __pageData,f as default};
